proof fn phi_1_mask_l1_pg_addr_low_30_bits_zero()
    ensures
        MASK_L1_PG_ADDR_SPEC & 0x3FFF_FFFF == 0,
{
    axiom_max_phyaddr_width_facts();
    assert(forall|low: usize, high: usize| low <= high && high < 64 ==> bitmask_inc!(low, high) & (!0usize >> (64 - low)) == 0) by (bit_vector);
}

proof fn phi_2_mask_l1_pg_addr_bit_30_set()
    ensures
        MASK_L1_PG_ADDR_SPEC & (1usize << 30) != 0,
{
    axiom_max_phyaddr_width_facts();
}

proof fn phi_3_mask_l1_pg_addr_subset_of_52bit_range()
    ensures
        MASK_L1_PG_ADDR_SPEC & !((1usize << 52) - 1) == 0,
{
    axiom_max_phyaddr_width_facts();
    assert(1usize << 52 == 0x10000000000000) by (compute);
}

proof fn phi_4_mask_l1_pg_addr_narrower_than_mask_addr()
    ensures
        MASK_L1_PG_ADDR_SPEC & bitmask_inc!(12usize, 29usize) == 0,
{
    axiom_max_phyaddr_width_facts();
    assert(bitmask_inc!(12usize, 29usize) == 0x3FFFF000) by (compute);
}

proof fn phi_5_mask_l1_width_depends_on_phyaddr_width()
